# Module providing integer stack data structure
class IntStack:
    _items: list[int]

    def __init__(self):
        self._items = []

    def push(self, value: int) -> None:
        self._items.append(value)

    def pop(self) -> int:
        return self._items.pop()

    def size(self) -> int:
        return len(self._items)
